	public byte[] getM_GALORDetailExcel(String filename, String fromdate, String todate, String currency,
			String dtltype, String type, String version) {

		try {
			logger.info("Generating Excel for BRRS_M_GALOR Details...");
			System.out.println("came to Detail download service");
			if (type.equals("ARCHIVAL") & version != null) {
				byte[] ARCHIVALreport = getM_GALORDetailExcelARCHIVAL(filename, fromdate, todate, currency, dtltype,
						type, version);
				return ARCHIVALreport;
			}

			XSSFWorkbook workbook = new XSSFWorkbook();
			XSSFSheet sheet = workbook.createSheet("M_GALOR_Detail");

			// Common border style
			BorderStyle border = BorderStyle.THIN;

			// Header style (left aligned)
			CellStyle headerStyle = workbook.createCellStyle();
			Font headerFont = workbook.createFont();
			headerFont.setBold(true);
			headerFont.setFontHeightInPoints((short) 10);
			headerStyle.setFont(headerFont);
			headerStyle.setAlignment(HorizontalAlignment.LEFT);
			headerStyle.setFillForegroundColor(IndexedColors.GREY_25_PERCENT.getIndex());
			headerStyle.setFillPattern(FillPatternType.SOLID_FOREGROUND);
			headerStyle.setBorderTop(border);
			headerStyle.setBorderBottom(border);
			headerStyle.setBorderLeft(border);
			headerStyle.setBorderRight(border);

			// Right-aligned header style for ACCT BALANCE
			CellStyle rightAlignedHeaderStyle = workbook.createCellStyle();
			rightAlignedHeaderStyle.cloneStyleFrom(headerStyle);
			rightAlignedHeaderStyle.setAlignment(HorizontalAlignment.RIGHT);

			// Default data style (left aligned)
			CellStyle dataStyle = workbook.createCellStyle();
			dataStyle.setAlignment(HorizontalAlignment.LEFT);
			dataStyle.setBorderTop(border);
			dataStyle.setBorderBottom(border);
			dataStyle.setBorderLeft(border);
			dataStyle.setBorderRight(border);

			// ACCT BALANCE style (right aligned with 3 decimals)
			CellStyle balanceStyle = workbook.createCellStyle();
			balanceStyle.setAlignment(HorizontalAlignment.RIGHT);
			balanceStyle.setDataFormat(workbook.createDataFormat().getFormat("#,##0"));
			balanceStyle.setBorderTop(border);
			balanceStyle.setBorderBottom(border);
			balanceStyle.setBorderLeft(border);
			balanceStyle.setBorderRight(border);

			// sanction style (right aligned with 3 decimals)
			CellStyle sanctionStyle = workbook.createCellStyle();
			sanctionStyle.setAlignment(HorizontalAlignment.RIGHT);
			sanctionStyle.setDataFormat(workbook.createDataFormat().getFormat("#,##0"));
			sanctionStyle.setBorderTop(border);
			sanctionStyle.setBorderBottom(border);
			sanctionStyle.setBorderLeft(border);
			sanctionStyle.setBorderRight(border);

			// Header row
			String[] headers = { "CUST ID", "ACCT NUMBER", "SCHM DESC", "ACCT BALANCE IN PULA", "APPROVED LIMIT",
					"REPORT LABEL", "REPORT ADDL CRITERIA 1", "REPORT ADDL CRITERIA 2", "REPORT ADDL CRITERIA 3",
					"REPORT_DATE" };

			XSSFRow headerRow = sheet.createRow(0);
			for (int i = 0; i < headers.length; i++) {
				Cell cell = headerRow.createCell(i);
				cell.setCellValue(headers[i]);
				if (i == 3 || i == 4) { // ACCT BALANCE
					cell.setCellStyle(rightAlignedHeaderStyle);
				} else {
					cell.setCellStyle(headerStyle);
				}
				sheet.setColumnWidth(i, 5000);
			}

			// Get data
			Date parsedToDate = new SimpleDateFormat("dd/MM/yyyy").parse(todate);
			List<M_GALOR_Detail_Entity> reportData = getDetailByDate(parsedToDate);

			if (reportData != null && !reportData.isEmpty()) {
				int rowIndex = 1;
				for (M_GALOR_Detail_Entity item : reportData) {
					XSSFRow row = sheet.createRow(rowIndex++);
					row.createCell(0).setCellValue(item.getCustId());
					row.createCell(1).setCellValue(item.getAcctNumber());
					row.createCell(2).setCellValue(item.getAcctName());

					// ACCT BALANCE (right aligned, 3 decimal places)
					Cell balanceCell = row.createCell(3);
					if (item.getAcctBalanceInpula() != null) {
						balanceCell.setCellValue(item.getAcctBalanceInpula().doubleValue());
					} else {
						balanceCell.setCellValue(0);
					}
					balanceCell.setCellStyle(balanceStyle);

					row.createCell(4).setCellValue(item.getReportLable());
					row.createCell(5).setCellValue(item.getReportAddlCriteria_1());
					row.createCell(6)
							.setCellValue(item.getReportDate() != null
									? new SimpleDateFormat("dd-MM-yyyy").format(item.getReportDate())
									: "");

					// Apply border style to all cells in the row
					for (int colIndex = 0; colIndex < headers.length; colIndex++) {
						Cell cell = row.getCell(colIndex);
						if (cell != null) {
							if (colIndex == 3) { // ACCT BALANCE
								cell.setCellStyle(balanceStyle);
							} else if (colIndex == 4) { // APPROVED LIMIT
								cell.setCellStyle(sanctionStyle);
							} else {
								cell.setCellStyle(dataStyle);
							}
						}
					}
				}
			} else {
				logger.info("No data found for BRRS_M_galor — only header will be written.");
			}

			// Write to byte[]
			ByteArrayOutputStream bos = new ByteArrayOutputStream();
			workbook.write(bos);
			workbook.close();
			logger.info("Excel generation completed with {} row(s).", reportData != null ? reportData.size() : 0);
			return bos.toByteArray();

		} catch (Exception e) {
			logger.error("Error generating BRRS_M_GALOR Excel", e);
			return new byte[0];
		}
	}

	@Transactional
	public void updateReport(M_GALOR_Manual_Summary_Entity updatedEntity) {

	    System.out.println("Entered updateReport service");
	    System.out.println("Report Date: " + updatedEntity.getReport_date());

	    // Fetch existing record
	    List<M_GALOR_Manual_Summary_Entity> list =
	            getManualSummaryByDate(updatedEntity.getReport_date());

	    String newRecordflag = "N";
	    if (list.isEmpty()) {
	    	newRecordflag ="Y";
	    	System.out.println("Record not found for REPORT_DATE: " + updatedEntity.getReport_date());
	        //throw new RuntimeException("Record not found for REPORT_DATE: " + updatedEntity.getReport_date());
	    }

	    M_GALOR_Manual_Summary_Entity existing;
	    if (list != null && !list.isEmpty()) {
	        existing = list.get(0);
	    } else {
	        existing = new M_GALOR_Manual_Summary_Entity();
	        existing.setReport_date(updatedEntity.getReport_date());
	    }

	    // Audit old copy
	    M_GALOR_Manual_Summary_Entity oldcopy = new M_GALOR_Manual_Summary_Entity();
	    BeanUtils.copyProperties(existing, oldcopy);

	    try {

	        int[] specialRows = {
	                22, 23, 57, 58, 60, 61, 64, 65,
	                67, 68, 111, 112, 113, 114
	        };

	        String[] fullFields = {
	                "product",
	                "botswana",
	                "south_africa",
	                "sadc",
	                "usa",
	                "uk",
	                "europe",
	                "india",
	                "sydney",
	                "uganda",
	                "c10",
	                "c11",
	                "c12",
	                "c13",
	                "c14",
	                "c15",
	                "c16",
	                "total"
	        };

	        for (int row : specialRows) {

	            String prefix = "R" + row + "_";

	            String[] activeFields = (row >= 111 && row <= 114)
	                    ? new String[] { "botswana" }
	                    : fullFields;

	            for (String field : activeFields) {

	                String getterName = "get" + prefix + field;
	                String setterName = "set" + prefix + field;

	                try {

	                    Method getter = M_GALOR_Manual_Summary_Entity.class
	                            .getMethod(getterName);

	                    Method setter = M_GALOR_Manual_Summary_Entity.class
	                            .getMethod(setterName, getter.getReturnType());

	                    Object newValue = getter.invoke(updatedEntity);

	                    System.out.println(
	                            "Updating field: " + prefix + field + " = " + newValue);

	                    setter.invoke(existing, newValue);

	                } catch (NoSuchMethodException e) {
	                    System.out.println(
	                            "Skipping missing field: " + prefix + field);
	                }
	            }
	        }

	    } catch (Exception e) {
	        throw new RuntimeException(
	                "Error while updating GALOR report fields", e);
	    }


	    // Audit & Save only if changes exist
	    String changes = auditService.getChanges(oldcopy, existing);

	    saveManualSummaryEntity(existing,newRecordflag);


	    if (!changes.isEmpty()) {

	        auditService.compareEntitiesmanual(
	                oldcopy,
	                existing,
	                updatedEntity.getReport_date().toString(),
	                "M GALOR Manual Summary Screen",
	                "M_GALOR_MANUAL_SUMMARY"
	        );

	        System.out.println("GALOR report updated successfully.");
	    }
	}
