	@Transactional
	public ResponseEntity<?> updateDetailEdit(HttpServletRequest request) {

	    try {


	        String acctNo = request.getParameter("acctNumber");
	        String provisionStr = request.getParameter("acctBalanceInpula");
	        String acctName = request.getParameter("acctName");
	        String reportDateStr = request.getParameter("reportDate");

			M_GALOR_Detail_Entity existing = findDetailByAcctNumber(acctNo);
			if (existing == null) {
				logger.warn("No record found for ACCT_NO: {}", acctNo);
				return ResponseEntity.status(HttpStatus.NOT_FOUND).body("Record not found for update.");
			}

	        // Audit copy
	        M_GALOR_Detail_Entity oldcopy = new M_GALOR_Detail_Entity();
	        BeanUtils.copyProperties(existing, oldcopy);

	        boolean isChanged = false;

	        if (acctName != null && !acctName.isEmpty()) {

	            if (existing.getAcctName() == null ||
	                    !existing.getAcctName().equals(acctName)) {

	                existing.setAcctName(acctName);
	                isChanged = true;

	                logger.info("Account name updated to {}", acctName);
	            }
	        }

	        if (provisionStr != null && !provisionStr.isEmpty()) {

	            BigDecimal newProvision = new BigDecimal(provisionStr);

	            if (existing.getAcctBalanceInpula() == null ||
	                    existing.getAcctBalanceInpula().compareTo(newProvision) != 0) {

	                existing.setAcctBalanceInpula(newProvision);
	                isChanged = true;

	                logger.info("Balance updated to {}", newProvision);
	            }
	        }

	        if (isChanged) {

	            saveDetailEntity(existing);

	            // Audit comparison
	            auditService.compareEntitiesmanual(
	                    oldcopy,
	                    existing,
	                    acctNo,
	                    "M GALOR Detail Screen",
	                    "BRRS_M_GALOR_DETAIL"
	            );

	            logger.info("Record updated successfully for account {}", acctNo);

	            String formattedDate = new SimpleDateFormat("dd-MM-yyyy")
	                    .format(new SimpleDateFormat("yyyy-MM-dd")
	                    .parse(reportDateStr));

	            TransactionSynchronizationManager.registerSynchronization(
	                    new TransactionSynchronizationAdapter() {

	                        @Override
	                        public void afterCommit() {

	                            try {

	                                logger.info(
	                                        "Transaction committed — calling BRRS_M_GALOR_SUMMARY_PROCEDURE({})",
	                                        formattedDate);

	                                jdbcTemplate.update(
	                                        "BEGIN BRRS_M_GALOR_SUMMARY_PROCEDURE(?); END;",
	                                        formattedDate);

	                                logger.info(
	                                        "Procedure executed successfully after commit.");

	                            } catch (Exception e) {

	                                logger.error(
	                                        "Error executing procedure after commit",
	                                        e);
	                            }
	                        }
	                    });

	            return ResponseEntity.ok("Record updated successfully!");

	        } else {

	            logger.info("No changes detected for ACCT_NO: {}", acctNo);
	            return ResponseEntity.ok("No changes were made.");
	        }

	    } catch (Exception e) {

	        logger.error("Error updating M_GALOR record", e);

	        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
	                .body("Error updating record: " + e.getMessage());
	    }
	}


	// Normal Email Excel
	public byte[] getEmail_M_GALORExcel(String filename, String reportId, String fromdate, String todate,
	        String currency, String dtltype, String type, BigDecimal version) throws Exception {
	    logger.info("Service: Starting Excel generation process in memory.");

	    logger.info("DownloadFile: reportId={}, filename={}", reportId, filename, type, version);

	    // Convert string to Date
	    Date reportDate = dateformat.parse(todate);

	    // Fetch data
	    List<M_GALOR_Summary_Entity1> dataList = getSummary1ByDate(reportDate);
	    List<M_GALOR_Summary_Entity2> dataList1 = getSummary2ByDate(reportDate);
	    List<M_GALOR_Manual_Summary_Entity> dataList2 = getManualSummaryByDate(reportDate);

	    if (dataList.isEmpty() && dataList1.isEmpty() && dataList2.isEmpty()) {
	        logger.warn("Service: No data found for M_GALOR report. Returning empty result.");
	        return new byte[0];
	    }

	    String templateDir = env.getProperty("output.exportpathtemp");
	    String templateFileName = filename;
	    System.out.println(filename);
	    Path templatePath = Paths.get(templateDir, templateFileName);
	    System.out.println(templatePath);

	    logger.info("Service: Attempting to load template from path: {}", templatePath.toAbsolutePath());

	    if (!Files.exists(templatePath)) {
	        throw new FileNotFoundException("Template file not found at: " + templatePath.toAbsolutePath());
	    }
	    if (!Files.isReadable(templatePath)) {
	        throw new SecurityException(
	                "Template file exists but is not readable (check permissions): " + templatePath.toAbsolutePath());
	    }

	    try (InputStream templateInputStream = Files.newInputStream(templatePath);
	            Workbook workbook = WorkbookFactory.create(templateInputStream);
	            ByteArrayOutputStream out = new ByteArrayOutputStream()) {

	        Sheet sheet = workbook.getSheetAt(0);

	        // --- Style Definitions ---
	        CreationHelper createHelper = workbook.getCreationHelper();

	        CellStyle dateStyle = workbook.createCellStyle();
	        dateStyle.setDataFormat(createHelper.createDataFormat().getFormat("dd-MM-yyyy"));
	        dateStyle.setBorderBottom(BorderStyle.THIN);
	        dateStyle.setBorderTop(BorderStyle.THIN);
	        dateStyle.setBorderLeft(BorderStyle.THIN);
	        dateStyle.setBorderRight(BorderStyle.THIN);

	        CellStyle textStyle = workbook.createCellStyle();
	        textStyle.setBorderBottom(BorderStyle.THIN);
	        textStyle.setBorderTop(BorderStyle.THIN);
	        textStyle.setBorderLeft(BorderStyle.THIN);
	        textStyle.setBorderRight(BorderStyle.THIN);

	        Font font = workbook.createFont();
	        font.setFontHeightInPoints((short) 8);
	        font.setFontName("Arial");

	        CellStyle numberStyle = workbook.createCellStyle();
	        numberStyle.setBorderBottom(BorderStyle.THIN);
	        numberStyle.setBorderTop(BorderStyle.THIN);
	        numberStyle.setBorderLeft(BorderStyle.THIN);
	        numberStyle.setBorderRight(BorderStyle.THIN);
	        numberStyle.setFont(font);
	        // --- End of Style Definitions ---

	        if (!dataList.isEmpty()) {
	            EmailpopulateEntity1Data(sheet, dataList.get(0), textStyle, numberStyle,dateStyle);
	        }

	        if (!dataList1.isEmpty()) {
	            EmailpopulateEntity2Data(sheet, dataList1.get(0), textStyle, numberStyle);
	        }

	        if (!dataList2.isEmpty()) {
	            EmailpopulateEntity3Data(sheet, dataList2.get(0), textStyle, numberStyle);
	        }
	        

	        // ❌ Removed formula evaluation to avoid extra 0 values
	        // workbook.getCreationHelper().createFormulaEvaluator().evaluateAll();

	        workbook.write(out);
	        logger.info("Service: Excel data successfully written to memory buffer ({} bytes).", out.size());
	        ServletRequestAttributes attrs = (ServletRequestAttributes) RequestContextHolder.getRequestAttributes();
			if (attrs != null) {
				HttpServletRequest request = attrs.getRequest();
				String userid = (String) request.getSession().getAttribute("USERID");
				auditService.createBusinessAudit(userid, "DOWNLOAD", "M_GALOR EMAIL ARCHIVAL SUMMARY", null, "BRRS_M_GALOR_ARCHIVALTABLE_SUMMARY");
			}
	        return out.toByteArray();
	    }
	}

