		// Archival Email Excel
	public byte[] BRRS_M_GALORARCHIVALEmailExcel(String filename, String reportId, String fromdate, String todate,
			String currency, String dtltype, String type, BigDecimal version) throws Exception {
		logger.info("Service: Starting Excel generation process in memory.");

		logger.info("DownloadFile: reportId={}, filename={}", reportId, filename, type, version);

		// Convert string to Date
		Date archivalReportDate = dateformat.parse(todate);
		List<M_GALOR_Archival_Summary_Entity1> dataList = getArchivalSummary1ByDateAndVersion(archivalReportDate, version);
		List<M_GALOR_Archival_Summary_Entity2> dataList1 = getArchivalSummary2ByDateAndVersion(archivalReportDate, version);
		List<M_GALOR_Manual_Archival_Summary_Entity> dataList2 = getArchivalManualSummaryByDateAndVersion(archivalReportDate, version);

		if (dataList.isEmpty() && dataList1.isEmpty() && dataList2.isEmpty()) {
			logger.warn("Service: No data found for M_GALOR report. Returning empty result.");
			return new byte[0];
		}
		// Fetch data

		/*
		 * List<M_GALOR_Archival_Summary_Entity1> dataList =
		 * m_galor_Archival_Summary1_Repo
		 * .getdatabydateListarchival(dateformat.parse(todate), version);
		 * List<M_GALOR_Archival_Summary_Entity2> dataList1 =
		 * m_galor_Archival_Summary2_Repo
		 * .getdatabydateListarchival(dateformat.parse(todate), version);
		 * List<M_GALOR_Manual_Archival_Summary_Entity> dataList2 =
		 * m_galor_Manual_Archival_Summary_Repo
		 * .getdatabydateListarchival(dateformat.parse(todate), version);
		 * 
		 * if (dataList.isEmpty()) { logger.
		 * warn("Service: No data found for M_GALOR report. Returning empty result.");
		 * return new byte[0]; }
		 */

		String templateDir = env.getProperty("output.exportpathtemp");
		String templateFileName = filename;
		System.out.println(filename);
		Path templatePath = Paths.get(templateDir, templateFileName);
		System.out.println(templatePath);

		logger.info("Service: Attempting to load template from path: {}", templatePath.toAbsolutePath());

		if (!Files.exists(templatePath)) {
			// This specific exception will be caught by the controller.
			throw new FileNotFoundException("Template file not found at: " + templatePath.toAbsolutePath());
		}
		if (!Files.isReadable(templatePath)) {
			// A specific exception for permission errors.
			throw new SecurityException(
					"Template file exists but is not readable (check permissions): " + templatePath.toAbsolutePath());
		}

		// This try-with-resources block is perfect. It guarantees all resources are
		// closed automatically.
		try (InputStream templateInputStream = Files.newInputStream(templatePath);
				Workbook workbook = WorkbookFactory.create(templateInputStream);
				ByteArrayOutputStream out = new ByteArrayOutputStream()) {

			Sheet sheet = workbook.getSheetAt(0);

			// --- Style Definitions ---
			CreationHelper createHelper = workbook.getCreationHelper();

			CellStyle dateStyle = workbook.createCellStyle();
			dateStyle.setDataFormat(createHelper.createDataFormat().getFormat("dd-MM-yyyy"));
			dateStyle.setBorderBottom(BorderStyle.THIN);
			dateStyle.setBorderTop(BorderStyle.THIN);
			dateStyle.setBorderLeft(BorderStyle.THIN);
			dateStyle.setBorderRight(BorderStyle.THIN);

			CellStyle textStyle = workbook.createCellStyle();
			textStyle.setBorderBottom(BorderStyle.THIN);
			textStyle.setBorderTop(BorderStyle.THIN);
			textStyle.setBorderLeft(BorderStyle.THIN);
			textStyle.setBorderRight(BorderStyle.THIN);

			// Create the font
			Font font = workbook.createFont();
			font.setFontHeightInPoints((short) 8); // size 8
			font.setFontName("Arial");

			CellStyle numberStyle = workbook.createCellStyle();
			// numberStyle.setDataFormat(createHelper.createDataFormat().getFormat("0.000"));
			numberStyle.setBorderBottom(BorderStyle.THIN);
			numberStyle.setBorderTop(BorderStyle.THIN);
			numberStyle.setBorderLeft(BorderStyle.THIN);
			numberStyle.setBorderRight(BorderStyle.THIN);
			numberStyle.setFont(font);
			// --- End of Style Definitions ---

			if (!dataList.isEmpty()) {
				ArchivalEmailpopulateEntity1Data(sheet, dataList.get(0), textStyle, numberStyle,dateStyle);
			}

			if (!dataList1.isEmpty()) {
				ArchivalEmailpopulateEntity2Data(sheet, dataList1.get(0), textStyle, numberStyle);
			}

			if (!dataList2.isEmpty()) {
				ArchivalEmailpopulateEntity3Data(sheet, dataList2.get(0), textStyle, numberStyle);
			}

			workbook.getCreationHelper().createFormulaEvaluator().evaluateAll();
			workbook.write(out);
			logger.info("Service: Excel data successfully written to memory buffer ({} bytes).", out.size());
			ServletRequestAttributes attrs = (ServletRequestAttributes) RequestContextHolder.getRequestAttributes();
			if (attrs != null) {
				HttpServletRequest request = attrs.getRequest();
				String userid = (String) request.getSession().getAttribute("USERID");
				auditService.createBusinessAudit(userid, "DOWNLOAD", "M_GALOR EMAIL ARCHIVAL SUMMARY", null, "BRRS_M_GALOR_ARCHIVALTABLE_SUMMARY");
			}
			return out.toByteArray();
		}
	}

